const webhook = $('Webhook email.received').first().json.body;
const clientResult = $input.first().json;

const prompt = `Tu es l'assistant IA d'un cabinet de courtage en assurances (GargarineV1). Analyse cet email et retourne UNIQUEMENT un JSON valide avec:
- "type": "client" | "prospect" | "assureur" | "prescripteur" | "autre"
- "urgence": "haute" | "normale" | "basse"
- "actionRequise": true | false
- "actionSuggeree": string ou null
- "resume": string (2 phrases max)
- "sentiment": "positif" | "neutre" | "negatif"
- "produitsMentionnes": string[] (parmi: SANTE_COLLECTIVE, PREVOYANCE_COLLECTIVE, PREVOYANCE_MADELIN, SANTE_MADELIN, RCP_PRO, PER, ASSURANCE_VIE, PROTECTION_JURIDIQUE)
- "reponseSuggeree": string (brouillon de reponse pro)

Email:
De: ${webhook.payload.expediteur}
Sujet: ${webhook.payload.sujet}
Extrait: ${webhook.payload.extrait}
Direction: ${webhook.payload.direction}
${clientResult.client ? `Client identifie: ${clientResult.client.raisonSociale} (${clientResult.client.statut})` : 'Client non identifie'}`;

return [{ json: { 
  prompt,
  emailId: webhook.payload.emailId,
  clientId: clientResult.client?.id || null,
  expediteur: webhook.payload.expediteur,
  sujet: webhook.payload.sujet
} }];
